export function getBlogPostBySlug(slug: string): BlogPost | undefined {
  return blogPosts.find((p) => p.slug === slug);
}

export function getBlogPostContent(post: BlogPost, locale: Locale): BlogPostLocaleContent {
  return post.content[locale as keyof typeof post.content] || post.content.en;
}

export function getAllBlogSlugs(): string[] {
  return blogPosts.map((p) => p.slug);
}

export function formatDate(dateStr: string, locale: Locale): string {
  const date = new Date(dateStr + "T00:00:00");
  const localeMap: Record<string, string> = { en: "en-US", es: "es-ES" };
  return date.toLocaleDateString(localeMap[locale] || "en-US", {
    year: "numeric",
    month: "long",
    day: "numeric",
  });
}
